_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz;


    //vec3 blurry = GetBlur3(vUv);
    vec3 crisp = texture(sampler_main, vUv).xyz;
    vec3 blurry = GetBlur2(vUv);
    ret = ((abs( crisp - blurry )*(q9+1.0))+((crisp+(blurry*.75))*.75))*(.73*q8);
    vec3 secblr = GetBlur1(vUv);
    ret = (ret+secblr)*.5;
    // darken (decay) over uTime
    ret = (ret - 0.009)*0.78;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;
  //pull four samples from the canvas
    vec2 uv1 = vec2(vUv.x,vUv.y);//no flip (bottom left)
    vec2 uv2 = uv1 * vec2(1.0, -1.0);//flip y(top left)
    vec2 uv3 = uv2 * vec2(-1.0, 1.0);//flip y&x(top right)
    vec2 uv4 = uv3 * vec2(1.0, -1.0);//flip x(bottom right)
    vec3 samp1 = texture(sampler_main, uv1).xyz;
    vec3 samp2 = texture(sampler_main, uv2).xyz;
    vec3 samp3 = texture(sampler_main, uv3).xyz;
    vec3 samp4 = texture(sampler_main, uv4).xyz;

//choose three mirror modes
    vec2 modeUV = vec2(q1,0.125);
    vec4 modePixA = texture(sampler_4wayLUT, modeUV).xyzw;
    modeUV = vec2(q1,0.375);
    vec4 modePixB = texture(sampler_4wayLUT, modeUV).xyzw;
    vec3 mode1 = (samp1*modePixA.x) + (min(min(samp1,samp2),min(samp3,samp4))*modePixB.y) +
      ((((vUv.x<0.5)*(vUv.y<0.5)*samp1)+((vUv.x<0.5)*(vUv.y>0.5)*samp2)+((vUv.x>0.5)*(vUv.y>0.5)*samp3)+((vUv.x>0.5)*(vUv.y<0.5)*samp4))*modePixA.y) +
      ((((vUv.x<0.5)*(vUv.y<0.5)*samp3)+((vUv.x<0.5)*(vUv.y>0.5)*samp4)+((vUv.x>0.5)*(vUv.y>0.5)*samp1)+((vUv.x>0.5)*(vUv.y<0.5)*samp2))*modePixA.z) +
      (max(max(samp1,samp2),max(samp3,samp4))*modePixA.w) + (((samp1+samp2+samp3+samp4)*0.25)*modePixB.x) +
      ((((vUv.x<0.5)*(vUv.y<0.5)*samp2)+((vUv.x<0.5)*(vUv.y>0.5)*samp1)+((vUv.x>0.5)*(vUv.y>0.5)*samp4)+((vUv.x>0.5)*(vUv.y<0.5)*samp3))*modePixB.z) +
      ((((vUv.x<0.5)*(vUv.y<0.5)*samp4)+((vUv.x<0.5)*(vUv.y>0.5)*samp3)+((vUv.x>0.5)*(vUv.y>0.5)*samp2)+((vUv.x>0.5)*(vUv.y<0.5)*samp1))*modePixB.w);
    modeUV = vec2(q2,0.125);
    modePixA = texture(sampler_4wayLUT, modeUV).xyzw;
    modeUV = vec2(q2,0.375);
    modePixB = texture(sampler_4wayLUT, modeUV).xyzw;
    vec3 mode2 = (samp1*modePixA.x) + (min(min(samp1,samp2),min(samp3,samp4))*modePixB.y) +
      ((((vUv.x<0.5)*(vUv.y<0.5)*samp1)+((vUv.x<0.5)*(vUv.y>0.5)*samp2)+((vUv.x>0.5)*(vUv.y>0.5)*samp3)+((vUv.x>0.5)*(vUv.y<0.5)*samp4))*modePixA.y) +
      ((((vUv.x<0.5)*(vUv.y<0.5)*samp3)+((vUv.x<0.5)*(vUv.y>0.5)*samp4)+((vUv.x>0.5)*(vUv.y>0.5)*samp1)+((vUv.x>0.5)*(vUv.y<0.5)*samp2))*modePixA.z) +
      (max(max(samp1,samp2),max(samp3,samp4))*modePixA.w) + (((samp1+samp2+samp3+samp4)*0.25)*modePixB.x) +
      ((((vUv.x<0.5)*(vUv.y<0.5)*samp2)+((vUv.x<0.5)*(vUv.y>0.5)*samp1)+((vUv.x>0.5)*(vUv.y>0.5)*samp4)+((vUv.x>0.5)*(vUv.y<0.5)*samp3))*modePixB.z) +
      ((((vUv.x<0.5)*(vUv.y<0.5)*samp4)+((vUv.x<0.5)*(vUv.y>0.5)*samp3)+((vUv.x>0.5)*(vUv.y>0.5)*samp2)+((vUv.x>0.5)*(vUv.y<0.5)*samp1))*modePixB.w);
    modeUV = vec2(q3,0.125);
    modePixA = texture(sampler_4wayLUT, modeUV).xyzw;
    modeUV = vec2(q3,0.375);
    modePixB = texture(sampler_4wayLUT, modeUV).xyzw;
    vec3 mode3 = (samp1*modePixA.x) + (min(min(samp1,samp2),min(samp3,samp4))*modePixB.y) +
      ((((vUv.x<0.5)*(vUv.y<0.5)*samp1)+((vUv.x<0.5)*(vUv.y>0.5)*samp2)+((vUv.x>0.5)*(vUv.y>0.5)*samp3)+((vUv.x>0.5)*(vUv.y<0.5)*samp4))*modePixA.y) +
      ((((vUv.x<0.5)*(vUv.y<0.5)*samp3)+((vUv.x<0.5)*(vUv.y>0.5)*samp4)+((vUv.x>0.5)*(vUv.y>0.5)*samp1)+((vUv.x>0.5)*(vUv.y<0.5)*samp2))*modePixA.z) +
      (max(max(samp1,samp2),max(samp3,samp4))*modePixA.w) + (((samp1+samp2+samp3+samp4)*0.25)*modePixB.x) +
      ((((vUv.x<0.5)*(vUv.y<0.5)*samp2)+((vUv.x<0.5)*(vUv.y>0.5)*samp1)+((vUv.x>0.5)*(vUv.y>0.5)*samp4)+((vUv.x>0.5)*(vUv.y<0.5)*samp3))*modePixB.z) +
      ((((vUv.x<0.5)*(vUv.y<0.5)*samp4)+((vUv.x<0.5)*(vUv.y>0.5)*samp3)+((vUv.x>0.5)*(vUv.y>0.5)*samp2)+((vUv.x>0.5)*(vUv.y<0.5)*samp1))*modePixB.w);

//define two blend modes
    mode1 *= min((2.0 - (q5*2.0)),1);  mode2 *= min((q5*2.0),1);
    modeUV = vec2(q4,0.625);  modePixA = texture(sampler_4wayLUT, modeUV).xyzw;
    modeUV = vec2(q4,0.875);  modePixB = texture(sampler_4wayLUT, modeUV).xyzw;
    float x1 = mode1.x + mode2.x;  float y1 = mode1.y + mode2.y;  float z1 = mode1.z + mode2.z;
    x1 += (x1>1.0)*-1.0;  y1 += (y1>1.0)*-1.0;  z1 += (z1>1.0)*-1.0;
    float x2 = mode1.x-mode2.x;  float y2 = mode1.y-mode2.y;  float z2 = mode1.z-mode2.z;
    x2 += (x2<0.0);  y2 += (y2<0.0);  z2 += (z2<0.0);
    vec3 blend1 = ((mode1 * mode2) * modePixA.x) + (max(mode1, mode2) * modePixA.y) +
      (((mode1 + mode2) * 0.5) * modePixA.z) + (min(mode1, mode2) * modePixA.w) +
      (min(mode1 + mode2, 1.0) * modePixB.x) + (vec3(x1, y1, z1) * modePixB.y) +
      (max(mode1 - mode2, 0.0) * modePixB.z) + (vec3(x2, y2, z2) * modePixB.w);
    blend1 *= min((2.0 - (q7*2.0)),1);  mode3 *= min((q7*2.0),1);
    modeUV = vec2(q6,0.625);  modePixA = texture(sampler_4wayLUT, modeUV).xyzw;
    modeUV = vec2(q6,0.875);  modePixB = texture(sampler_4wayLUT, modeUV).xyzw;
    x1 = blend1.x + mode3.x;  y1 = blend1.y + mode3.y;  z1 = blend1.z + mode3.z;
    x1 += (x1>1.0)*-1.0;  y1 += (y1>1.0)*-1.0;  z1 += (z1>1.0)*-1.0;
    x2 = blend1.x - mode3.x;  y2 = blend1.y - mode3.y;  z2 = blend1.z - mode3.z;
    x2 += (x2<0.0);  y2 += (y2<0.0);  z2 += (z2<0.0);
    vec3 blend2 = ((blend1 * mode3) * modePixA.x) + (max(blend1, mode3) * modePixA.y) +
      (((blend1 + mode3) * 0.5) * modePixA.z) + (min(blend1, mode3) * modePixA.w) +
      (min(blend1 + mode3, 1.0) * modePixB.x) + (vec3(x1, y1, z1) * modePixB.y) +
      (max(blend1 - mode3, 0.0) * modePixB.z) + (vec3(x2, y2, z2) * modePixB.w);


    ret = blend2;

  fragColor = ret;
}
